package com.crapi.interceptor;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import java.util.Set;
import org.springframework.stereotype.Component;
import org.springframework.web.servlet.HandlerInterceptor;

@Component
public class DeprecatedVersionInterceptor implements HandlerInterceptor {

  private static final Set<String> RETIRED_PATHS =
      Set.of(
          "/identity/api/auth/v2.7/user/login-with-token"
          // Add future retirements here
          );

  @Override
  public boolean preHandle(
      HttpServletRequest req, HttpServletResponse res, Object handler) throws Exception {
    if (RETIRED_PATHS.contains(req.getRequestURI())) {
      res.setStatus(410);
      res.setContentType("application/json");
      res.getWriter()
          .write("{\"message\":\"Endpoint retired.\",\"status\":410}");
      return false;
    }
    if (req.getRequestURI().contains("/v2.")) {
      res.addHeader("Deprecation", "true");
      res.addHeader("Sunset", "Sat, 01 Jan 2022 00:00:00 GMT");
      res.addHeader("Link", "</identity/api/auth/login>; rel=\"successor-version\"");
    }
    return true;
  }
}

package com.crapi.config;

import com.crapi.interceptor.DeprecatedVersionInterceptor;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.Configuration;
import org.springframework.web.servlet.config.annotation.InterceptorRegistry;
import org.springframework.web.servlet.config.annotation.WebMvcConfigurer;

@Configuration
public class WebMvcConfig implements WebMvcConfigurer {

  @Autowired private DeprecatedVersionInterceptor deprecatedInterceptor;

  @Override
  public void addInterceptors(InterceptorRegistry registry) {
    registry.addInterceptor(deprecatedInterceptor);
  }
}
